class Solution {
public:
    int minimizeXor(int num1, int num2) {
        int count = __builtin_popcount(num2);
        int ans = 0;
        for (int i = 30; i >= 0; --i) {
            if (count > 0 && ((num1 >> i) & 1) == 0) {
                ans |= (1 << i);
                --count;
            }
        }
        for (int i = 0; i < 31; ++i) {
            if (count > 0 && ((num1 >> i) & 1) == 1) {
                ans |= (1 << i);
                --count;
            }
        }
        return ans;
    }
};
